mapper.select:
select c.handling_officer_id as officer_id, u.name as officer_name, count(1) as assigned_count, sum(case when c.status in ('DECIDED', 'EXECUTED', 'ARCHIVED') then 1 else 0 end) as completed_count, sum(case when c.is_overdue = 1 then 1 else 0 end) as overdue_count, round(sum(case when c.status in ('DECIDED', 'EXECUTED', 'ARCHIVED') then 1 else 0 end) * 100.0 / count(1), 2) as completion_rate from cases c left join users u on u.id = c.handling_officer_id
c.handling_officer_id is not null
group by c.handling_officer_id, u.name order by completion_rate desc, assigned_count desc limit #{topN}

select date_format(clr.reviewed_at, '%Y-%m') as period, count(1) as total_reviewed, sum(case when clr.review_status = 'APPROVED' then 1 else 0 end) as approved_count, round(sum(case when clr.review_status = 'APPROVED' then 1 else 0 end) * 100.0 / count(1), 2) as pass_rate from case_legal_reviews clr
and clr.reviewed_at >= #{startTime}
and clr.reviewed_at <= #{endTime}
group by date_format(clr.reviewed_at, '%Y-%m') order by period asc
